def clamp(x, lo, hi):
    return max(min(x, hi), lo)
```

```python
def unique(lst):
    seen = set()
    result = []
    for item in lst:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result
```

```python
def intersection(a, b):
    # Use set intersection to find common elements
    return list(set(a) & set(b))
```

```python
def char_frequency(s):
    freq_dict = {}
    for char in s:
        if char in freq_dict:
            freq_dict[char] += 1
        else:
            freq_dict[char] = 1
    return freq_dict
```
